// Unit 16 — Si Pudiera...
// The Conditional

export default {n:16,lang:"es",srcLang:"en",track:"v2",title:"Si Pudiera...",sub:"The Conditional",icon:"💭",level:"A2.4",color:"#7B5EE8",lessons:[
  {id:"esp16l1",title:"Me gustaría",icon:"✨",xp:15,board:true,steps:[
        {type:"intro",title:"Me gustaría",desc:"Learn to express polite wishes and desires with me gustaría + infinitivo. This is one of the most useful phrases in Spanish.",goals:["Use me gustaría + infinitive for polite wishes","Express desires about travel, food, and activities","Compare me gusta (I like) with me gustaría (I would like)"]},
        {type:"teach",trg:"Me gustaría",src:"I would like",pos:"verb",gender:null,phonetic:"meh goos-ta-REE-a",note:"Me gustaría + infinitive expresses a polite wish. Much softer than quiero.",example:"A: ¿Qué te gustaría hacer este verano?\nB: Me gustaría viajar a España.\nA: ¡A mí también me gustaría!",exampleSrc:"A: What would you like to do this summer?\nB: I would like to travel to Spain.\nA: I would like that too!",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"teach",trg:"Me gustaría viajar",src:"I would like to travel",pos:"verb",gender:null,phonetic:"meh goos-ta-REE-a vya-HAR",note:"Gustaría + infinitive for activities you dream about doing.",example:"A: ¿Tienes planes para las vacaciones?\nB: Me gustaría viajar a Japón algún día.\nA: Es un país increíble.",exampleSrc:"A: Do you have plans for the vacation?\nB: I would like to travel to Japan someday.\nA: It is an incredible country.",funFact:"A regular -ar verb, the largest Spanish verb group. Learn this pattern and you unlock hundreds of verbs."},
        {type:"teach",trg:"Me gustaría comer",src:"I would like to eat",pos:"intj",gender:null,phonetic:"meh goos-ta-REE-a ko-MER",note:"Perfect for ordering in restaurants or expressing food preferences.",example:"A: ¿Qué te gustaría comer?\nB: Me gustaría comer paella.\nA: Conozco un restaurante muy bueno.",exampleSrc:"A: What would you like to eat?\nB: I would like to eat paella.\nA: I know a very good restaurant.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Te gustaría",src:"You would like",pos:"intj",gender:null,phonetic:"teh goos-ta-REE-a",note:"Used to make invitations. Very polite way to ask someone to do something.",example:"A: ¿Te gustaría ir al cine esta noche?\nB: ¡Sí, me encantaría!\nA: Perfecto, paso por ti a las ocho.",exampleSrc:"A: Would you like to go to the movies tonight?\nB: Yes, I would love to!\nA: Perfect, I'll pick you up at eight.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Nos gustaría",src:"We would like",pos:"intj",gender:null,phonetic:"nos goos-ta-REE-a",note:"Nos gustaría for group wishes. Common at restaurants and hotels.",example:"A: Buenos días, ¿en qué puedo ayudarles?\nB: Nos gustaría reservar una mesa para cuatro.\nA: Por supuesto, ¿a qué hora?",exampleSrc:"A: Good morning, how can I help you?\nB: We would like to reserve a table for four.\nA: Of course, at what time?",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"tip",title:"Me gusta vs me gustaría",text:"Me gusta = I like (fact, present reality)\nMe gusta el chocolate. (I like chocolate.)\n\nMe gustaría = I would like (wish, hypothetical)\nMe gustaría probar ese chocolate. (I would like to try that chocolate.)\n\nGustaría is softer, more polite, and expresses something not yet real."},
        {type:"mc",q:"'Me gustaría aprender italiano' means:",opts:["I would like to learn Italian","I like learning Italian","I learned Italian","I am learning Italian"],ans:"I would like to learn Italian",hint:"Gustaría expresses a wish, not a current reality."},
        {type:"mc",q:"At a restaurant, politely ordering food:",opts:["Quiero paella","Me gustaría comer paella","Dame paella","Necesito paella"],ans:"Me gustaría comer paella",hint:"The most polite option uses the conditional form of gustar."},
        {type:"fb",opts:["gustaría","gusta","gustó","gustaba"],hint:"Would you like to go? The conditional form makes this an invitation.",s:"¿Te {1} ir a la playa mañana?",a:"gustaría"},
        {type:"mc",q:"'Nos gustaría reservar una habitación' is something you say at:",opts:["A hospital","A school","A hotel","A gym"],ans:"A hotel",hint:"Reserving a room is typical of this type of establishment."},
        {type:"teach",trg:"Le gustaría",src:"He/she/you (formal) would like",pos:"noun",gender:null,phonetic:"leh goos-ta-REE-a",note:"Le gustaría for formal you (usted) or third person. Very polite in service.",example:"A: ¿Le gustaría un café, señor?\nB: Sí, me gustaría un café con leche.\nA: Enseguida se lo traigo.",exampleSrc:"A: Would you like a coffee, sir?\nB: Yes, I would like a coffee with milk.\nA: I will bring it right away.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"Les gustaría",src:"They / you all would like",pos:"intj",gender:null,phonetic:"les goos-ta-REE-a",note:"Les gustaría for they or ustedes. Plural form of the polite wish.",example:"A: ¿Les gustaría visitar el museo?\nB: ¡Sí! Nos gustaría mucho.\nA: Abre a las diez.",exampleSrc:"A: Would you all like to visit the museum?\nB: Yes! We would like that very much.\nA: It opens at ten.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"fb",opts:["Me","Te","Le","Se"],hint:"First person: I would like. Which pronoun goes with yo?",s:"{1} gustaría vivir en Barcelona.",a:"Me"},
        {type:"drag_fill",hint:"I would like to travel (me) and you would like to stay home (te).",s:"A mí {1} viajar y a ti {2} quedarte en casa.",blanks:{"1":"me gustaría","2":"te gustaría"},pool:["me gustaría","te gustaría","le gustaría","nos gustaría"]},
        {type:"match",pairs:[
          {trg:"Me gustaría",src:"I would like"},
          {trg:"Te gustaría",src:"You would like"},
          {trg:"Le gustaría",src:"He/she would like"},
          {trg:"Nos gustaría",src:"We would like"},
          {trg:"Les gustaría",src:"They would like"}
        ]},
        {type:"mc",q:"Which is MORE polite when ordering?",opts:["Quiero un café","Dame un café","Necesito un café","Me gustaría un café"],ans:"Me gustaría un café",hint:"The conditional softens the request into a wish rather than a demand."},
        {type:"fb",opts:["Le","Me","Se","Lo"],hint:"Asking a formal you (usted) if they would like to try it.",s:"¿{1} gustaría probar la tortilla española?",a:"Le"},
        {type:"mc",q:"'Me gustaría ser médico' expresses:",opts:["I would like to be a doctor","I was a doctor","I am a doctor","I have to be a doctor"],ans:"I would like to be a doctor",hint:"Gustaría + ser + profession expresses a dream or aspiration."}
  ]},
  {id:"esp16l2",title:"Hablaría",icon:"📝",xp:15,board:true,steps:[
        {type:"intro",title:"Hablaría",desc:"Learn the conditional tense for all regular verbs. Good news: like the future, one set of endings works for -AR, -ER, and -IR verbs.",goals:["Conjugate regular verbs in the conditional","Recognize conditional endings (-ía, -ías, -ía, -íamos, -ían)","See the connection between future stems and conditional endings"]},
        {type:"teach",trg:"hablaría",src:"I would speak",pos:"verb",gender:null,phonetic:"ah-bla-REE-a",note:"Conditional: full infinitive + -ía. Same stem as the future tense.",example:"A: ¿Hablarías con el jefe sobre el problema?\nB: Sí, yo hablaría con él, pero no está hoy.\nA: Entonces habla con él mañana.",exampleSrc:"A: Would you speak with the boss about the problem?\nB: Yes, I would speak with him, but he is not here today.\nA: Then speak with him tomorrow.",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"teach",trg:"hablarías",src:"You would speak",pos:"noun",gender:null,phonetic:"ah-bla-REE-as",note:"Tú form. Notice the accent on the i: hablarÍas.",example:"A: ¿Hablarías en público?\nB: No sé, me pondría muy nervioso.\nA: Con práctica se aprende.",exampleSrc:"A: Would you speak in public?\nB: I don't know, I would get very nervous.\nA: You learn with practice.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"hablaríamos",src:"We would speak",pos:"noun",gender:null,phonetic:"ah-bla-REE-a-mos",note:"Nosotros form. The accent stays on the i: hablaríamos.",example:"A: En un mundo ideal, ¿qué idioma hablaríamos?\nB: Hablaríamos todos español, claro.\nA: Yo preferiría el italiano.",exampleSrc:"A: In an ideal world, what language would we speak?\nB: We would all speak Spanish, of course.\nA: I would prefer Italian.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"hablarían",src:"They would speak",pos:"noun",gender:null,phonetic:"ah-bla-REE-an",note:"Ellos/ustedes form. Hablar + ían.",example:"A: ¿Tus amigos hablarían español en la reunión?\nB: No, hablarían en inglés.\nA: Deberían practicar más.",exampleSrc:"A: Would your friends speak Spanish in the meeting?\nB: No, they would speak in English.\nA: They should practice more.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"verb_table",title:"Conditional: hablar",note:"Yo and él/ella/usted share the same form: hablaría.",groups:[
          {label:"Singular",rows:[{"0":"yo","1":"hablaría"},{"0":"tú","1":"hablarías"},{"0":"él/ella/usted","1":"hablaría"}]},
          {label:"Plural",rows:[{"0":"nosotros","1":"hablaríamos"},{"0":"ellos/ellas/ustedes","1":"hablarían"}]}
        ],label:"Full infinitive + conditional endings"},
        {type:"tip",title:"Conditional = Future stem + imperfect endings",text:"The conditional combines two things you already know:\n\nFuture stem (full infinitive for regular verbs)\n+ Imperfect -ER/-IR endings (-ía, -ías, -ía, -íamos, -ían)\n\nFuture: hablar + é = hablaré (I will speak)\nConditional: hablar + ía = hablaría (I would speak)\n\nAll endings have an accent on the í. All three verb groups use the same endings."},
        {type:"mc",q:"The conditional endings are the same for -AR, -ER, and -IR verbs:",opts:["True","False, each group has different endings","Only -ER and -IR share endings","There are no conditional endings"],ans:"True",hint:"Just like the future, one set of endings covers all verb groups."},
        {type:"mc",q:"'She would eat' (comer) in the conditional is:",opts:["comerá","comería","comía","come"],ans:"comería",hint:"Full infinitive comer + the third person conditional ending."},
        {type:"fb",opts:["viviría","viviré","vivía","vivo"],hint:"I would live. Full infinitive vivir + the conditional yo ending.",s:"Yo {1} en España si pudiera.",a:"viviría"},
        {type:"teach",trg:"comería",src:"I would eat",pos:"verb",gender:null,phonetic:"ko-meh-REE-a",note:"Comer + ía. Regular -ER verb, same pattern as hablar.",example:"A: ¿Qué comerías en tu último día?\nB: Comería paella y churros.\nA: ¡Buena elección!",exampleSrc:"A: What would you eat on your last day?\nB: I would eat paella and churros.\nA: Good choice!",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"teach",trg:"viviría",src:"I would live",pos:"verb",gender:null,phonetic:"vee-vee-REE-a",note:"Vivir + ía. Regular -IR verb, exact same endings.",example:"A: ¿Dónde vivirías si pudieras elegir?\nB: Viviría en una isla tropical.\nA: Yo también, junto al mar.",exampleSrc:"A: Where would you live if you could choose?\nB: I would live on a tropical island.\nA: Me too, by the sea.",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"mc",q:"Nosotros ___ más si tuviéramos tiempo.",opts:["estudiamos","estudiaremos","estudiaríamos","estudiábamos"],ans:"estudiaríamos",hint:"We would study. Full infinitive + nosotros conditional ending."},
        {type:"fb",opts:["comprarían","compraría","comprarán","compraban"],hint:"They would buy. Full infinitive comprar + third person plural conditional.",s:"Ellos {1} una casa más grande.",a:"comprarían"},
        {type:"drag_fill",hint:"I would sing (cantar, yo) and you would dance (bailar, tú).",s:"Yo {1} y tú {2} en un mundo perfecto.",blanks:{"1":"cantaría","2":"bailarías"},pool:["cantaría","bailarías","cantarías","bailaría"]},
        {type:"match",pairs:[{trg:"-ía",src:"yo / él/ella"},{trg:"-ías",src:"tú"},{trg:"-íamos",src:"nosotros"},{trg:"-ían",src:"ellos/ustedes"}]},
        {type:"mc",q:"Which form is shared between yo and él/ella in the conditional?",opts:["-ían","-ías","-íamos","-ía"],ans:"-ía",hint:"First person and third person singular look identical in the conditional."},
        {type:"fb",opts:["Hablarías","Hablaría","Hablarán","Hablarías"],hint:"Would you speak? Informal you, conditional tense.",s:"¿{1} español en tu trabajo?",a:"Hablarías"}
  ]},
  {id:"esp16l3",title:"Tendría, haría",icon:"⚡",xp:15,board:true,steps:[
        {type:"intro",title:"Tendría, haría",desc:"The conditional uses the SAME irregular stems as the future tense. If you know tendré, you know tendría!",goals:["Apply irregular future stems to conditional endings","Conjugate tener, hacer, decir, poder, poner, saber, salir, venir, querer","See the pattern: same stem, different endings"]},
        {type:"teach",trg:"tendría",src:"I would have",pos:"noun",gender:null,phonetic:"ten-DREE-a",note:"Tener: tendr- + ía. Same stem as tendré (future). Only the ending changes.",example:"A: ¿Qué harías con un millón de euros?\nB: Tendría una casa en la playa.\nA: ¡Yo también tendría una!",exampleSrc:"A: What would you do with a million euros?\nB: I would have a house on the beach.\nA: I would have one too!",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"haría",src:"I would do / make",pos:"noun",gender:null,phonetic:"ah-REE-a",note:"Hacer: har- + ía. Same shortened stem as haré (future).",example:"A: ¿Qué harías en mi situación?\nB: Yo haría lo mismo que tú.\nA: Gracias, eso me tranquiliza.",exampleSrc:"A: What would you do in my situation?\nB: I would do the same as you.\nA: Thanks, that calms me down.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"diría",src:"I would say / tell",pos:"noun",gender:null,phonetic:"dee-REE-a",note:"Decir: dir- + ía. Very short stem, same as diré (future).",example:"A: ¿Qué le dirías a tu yo del pasado?\nB: Le diría que no se preocupe tanto.\nA: Es un buen consejo.",exampleSrc:"A: What would you say to your past self?\nB: I would tell him not to worry so much.\nA: That is good advice.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"podría",src:"I would be able to / could",pos:"noun",gender:null,phonetic:"po-DREE-a",note:"Poder: podr- + ía. Podría is very common for polite requests (could you?).",example:"A: ¿Podrías ayudarme con esto?\nB: Sí, podría ayudarte después de comer.\nA: Perfecto, te espero.",exampleSrc:"A: Could you help me with this?\nB: Yes, I could help you after lunch.\nA: Perfect, I will wait for you.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"pondría",src:"I would put",pos:"noun",gender:null,phonetic:"pon-DREE-a",note:"Poner: pondr- + ía. Same -dr- stem as pondré (future).",example:"A: ¿Dónde pondrías este cuadro?\nB: Yo lo pondría encima del sofá.\nA: Buena idea, ahí queda bien.",exampleSrc:"A: Where would you put this painting?\nB: I would put it above the sofa.\nA: Good idea, it looks nice there.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"tip",title:"Future stem = Conditional stem",text:"Every irregular future stem works in the conditional too:\n\n-dr- group: tendr-, pondr-, saldr-, vendr-\nShortened group: har-, dir-, sabr-, podr-, querr-\n\nFuture: tendré, haré, diré...\nConditional: tendría, haría, diría...\n\nSame stem. Different ending (-é vs -ía)."},
        {type:"verb_table",title:"Irregular conditional stems",note:"All use the standard conditional endings. Only the stems are irregular.",groups:[
          {
            label:"-dr- group",
            rows:[{"0":"tener","1":"tendría, tendrías, tendría, tendríamos, tendrían"},{"0":"poner","1":"pondría, pondrías..."},{"0":"salir","1":"saldría, saldrías..."},{"0":"venir","1":"vendría, vendrías..."}]
          },
          {
            label:"Shortened group",
            rows:[{"0":"hacer","1":"haría, harías..."},{"0":"decir","1":"diría, dirías..."},{"0":"saber","1":"sabría, sabrías..."},{"0":"poder","1":"podría, podrías..."},{"0":"querer","1":"querría, querrías..."}]
          }
        ],label:"Irregular stem + conditional endings (-ía, -ías, -ía, -íamos, -ían)"},
        {type:"mc",q:"The conditional of 'tener' (yo) is:",opts:["tendría","tenería","teniría","tenría"],ans:"tendría",hint:"Same stem as the future (tendr-) plus the conditional ending."},
        {type:"mc",q:"Ella ___ la verdad si alguien le preguntara.",opts:["deciría","diría","dirá","dice"],ans:"diría",hint:"Decir has the shortened stem dir- in both future and conditional."},
        {type:"fb",opts:["Podrías","Puedes","Poderías","Podrás"],hint:"Could you help me? Conditional of poder, tú form.",s:"¿{1} ayudarme con la mudanza?",a:"Podrías"},
        {type:"mc",q:"Nosotros ___ de casa si encontráramos algo mejor.",opts:["salimos","saliríamos","saldríamos","saldremos"],ans:"saldríamos",hint:"We would leave. Salir has the irregular stem saldr- plus nosotros ending."},
        {type:"teach",trg:"sabría",src:"I would know",pos:"noun",gender:null,phonetic:"sa-BREE-a",note:"Saber: sabr- + ía. Would you know how to...?",example:"A: ¿Sabrías llegar a su casa sin GPS?\nB: No, no sabría. Me pierdo siempre.\nA: Yo tampoco sabría.",exampleSrc:"A: Would you know how to get to their house without GPS?\nB: No, I wouldn't know. I always get lost.\nA: I wouldn't know either.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"querría",src:"I would want",pos:"noun",gender:null,phonetic:"keh-RREE-a",note:"Querer: querr- + ía. Double r in all forms. Also used as a polite wish.",example:"A: ¿Querrías cambiar algo de tu vida?\nB: Querría tener más tiempo libre.\nA: Todos querríamos eso.",exampleSrc:"A: Would you want to change something about your life?\nB: I would want to have more free time.\nA: We would all want that.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"fb",opts:["sabría","saberá","sabré","sabía"],hint:"I would not know. Saber in the conditional, first person.",s:"Yo no {1} qué hacer sin ti.",a:"sabría"},
        {type:"drag_fill",hint:"He would do (hacer, irregular) more exercise and she would eat (comer, regular) less sugar.",s:"Él {1} más ejercicio y ella {2} menos azúcar.",blanks:{"1":"haría","2":"comería"},pool:["haría","comería","harían","comerían"]},
        {type:"match",pairs:[{trg:"tendría",src:"I would have"},{trg:"haría",src:"I would do"},{trg:"diría",src:"I would say"},{trg:"podría",src:"I could"},{trg:"sabría",src:"I would know"},{trg:"querría",src:"I would want"}]},
        {type:"mc",q:"Which verb has a double -rr- in its conditional stem?",opts:["Hacer (har-)","Poder (podr-)","Saber (sabr-)","Querer (querr-)"],ans:"Querer (querr-)",hint:"This verb keeps both r's when it drops the final -e-."}
  ]},
  {id:"esp16l4",title:"¿Podría...?",icon:"🎩",xp:15,board:true,steps:[
        {type:"intro",title:"¿Podría...?",desc:"The conditional is the key to polite Spanish. Learn to make requests, ask favors, and speak with elegance.",goals:["Make polite requests with podría, sería, tendría","Ask for help and favors politely","Recognize formal service language"]},
        {type:"teach",trg:"¿Podría ayudarme?",src:"Could you help me?",pos:"intj",gender:null,phonetic:"po-DREE-a ah-yoo-DAR-meh",note:"The most common polite request formula. Works everywhere.",example:"A: Disculpe, ¿podría ayudarme?\nB: Claro, ¿qué necesita?\nA: Busco la estación de tren.",exampleSrc:"A: Excuse me, could you help me?\nB: Of course, what do you need?\nA: I am looking for the train station.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"¿Le importaría...?",src:"Would you mind...?",pos:"verb",gender:null,phonetic:"leh im-por-ta-REE-a",note:"Very formal and polite. Le importaría + infinitive. Used with strangers.",example:"A: ¿Le importaría abrir la ventana?\nB: No, claro que no. Enseguida.\nA: Muchas gracias.",exampleSrc:"A: Would you mind opening the window?\nB: No, of course not. Right away.\nA: Thank you very much.",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"teach",trg:"¿Sería posible...?",src:"Would it be possible...?",pos:"intj",gender:null,phonetic:"seh-REE-a po-SEE-bleh",note:"Very formal. Used in professional settings, hotels, offices.",example:"A: ¿Sería posible cambiar la fecha?\nB: Déjeme revisar. Sí, sería posible.\nA: Perfecto, me vendría mejor el viernes.",exampleSrc:"A: Would it be possible to change the date?\nB: Let me check. Yes, it would be possible.\nA: Perfect, Friday would suit me better.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"¿Tendría tiempo?",src:"Would you have time?",pos:"intj",gender:null,phonetic:"ten-DREE-a TYEM-po",note:"Polite way to ask about someone's availability. Softer than tienes tiempo.",example:"A: ¿Tendría tiempo para una reunión mañana?\nB: Tendría tiempo por la tarde.\nA: Perfecto, ¿a las tres?",exampleSrc:"A: Would you have time for a meeting tomorrow?\nB: I would have time in the afternoon.\nA: Perfect, at three?",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"¿Me podría decir...?",src:"Could you tell me...?",pos:"verb",gender:null,phonetic:"meh po-DREE-a deh-SEER",note:"Combining podría with another verb. Very natural for asking information.",example:"A: Disculpe, ¿me podría decir la hora?\nB: Son las cuatro y media.\nA: Muchas gracias.",exampleSrc:"A: Excuse me, could you tell me the time?\nB: It is four thirty.\nA: Thank you very much.",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"tip",title:"Polite request formulas",text:"From most casual to most formal:\n\n¿Puedes...? (Can you? casual)\n¿Podrías...? (Could you? polite)\n¿Podría...? (Could you? formal)\n¿Le importaría...? (Would you mind? very formal)\n¿Sería posible...? (Would it be possible? most formal)\n\nIn customer service, shops, and with strangers, use podría or higher."},
        {type:"mc",q:"The most formal way to ask for help is:",opts:["¿Le importaría ayudarme?","¿Puedes ayudarme?","¿Podrías ayudarme?","¿Me ayudas?"],ans:"¿Le importaría ayudarme?",hint:"The formula with 'would you mind' is the highest level of politeness."},
        {type:"mc",q:"At a hotel reception, you ask to change rooms:",opts:["Quiero otra habitación","¿Sería posible cambiar de habitación?","Dame otra habitación","Cambio de habitación"],ans:"¿Sería posible cambiar de habitación?",hint:"Hotels and formal services call for the most polite conditional formula."},
        {type:"fb",opts:["Podría","Puede","Puedes","Podrás"],hint:"Could you repeat that? Formal polite request in the conditional.",s:"¿{1} repetir eso, por favor?",a:"Podría"},
        {type:"teach",trg:"Me vendría bien",src:"It would suit me / It would be good for me",pos:"intj",gender:null,phonetic:"meh ven-DREE-a BYEN",note:"Vendría from venir (irregular). Very natural for scheduling.",example:"A: ¿Te va bien el martes?\nB: Me vendría mejor el miércoles.\nA: Vale, el miércoles entonces.",exampleSrc:"A: Does Tuesday work for you?\nB: Wednesday would suit me better.\nA: Okay, Wednesday then.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Debería",src:"I should / ought to",pos:"noun",gender:null,phonetic:"deh-beh-REE-a",note:"Deber + ía. Used for advice and suggestions. Softer than debes.",example:"A: Estoy muy cansado últimamente.\nB: Deberías dormir más.\nA: Lo sé, pero tengo mucho trabajo.",exampleSrc:"A: I am very tired lately.\nB: You should sleep more.\nA: I know, but I have a lot of work.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"mc",q:"'Deberías estudiar más' is:",opts:["A command","A fact about the past","Polite advice","A question"],ans:"Polite advice",hint:"The conditional of deber softens the suggestion into friendly ___."},
        {type:"fb",opts:["importaría","importa","importó","importará"],hint:"Would you mind? The conditional of importar for very polite requests.",s:"¿Le {1} cerrar la puerta?",a:"importaría"},
        {type:"drag_fill",hint:"Could you tell me where the bank is? Polite conditional + present location.",s:"¿{1} decirme dónde {2} el banco?",blanks:{"1":"Podría","2":"está"},pool:["Podría","está","Puede","estará"]},
        {type:"match",pairs:[
          {trg:"¿Podría...?",src:"Could you...?"},
          {trg:"¿Le importaría...?",src:"Would you mind...?"},
          {trg:"¿Sería posible...?",src:"Would it be possible...?"},
          {trg:"Debería",src:"I should"},
          {trg:"Me vendría bien",src:"It would suit me"}
        ]},
        {type:"mc",q:"A waiter asks '¿Le gustaría ver la carta de postres?' This means:",opts:["Do you want dessert?","You must order dessert","Here is the dessert menu","Would you like to see the dessert menu?"],ans:"Would you like to see the dessert menu?",hint:"Le gustaría is the formal conditional of gustar, making it a polite offer."},
        {type:"fb",opts:["Deberías","Debes","Debías","Deberás"],hint:"You should go. The conditional of deber gives gentle advice.",s:"{1} ir al médico si no te sientes bien.",a:"Deberías"},
        {type:"mc",q:"Which phrase would you use to suggest a meeting time politely?",opts:["Me vendría bien a las tres","Nos vemos a las tres","Son las tres","Eran las tres"],ans:"Me vendría bien a las tres",hint:"This conditional phrase expresses what time would suit you."}
  ]},
  {id:"esp16l5",title:"Si tuviera...",icon:"🌈",xp:15,board:true,steps:[
        {type:"intro",title:"Si tuviera...",desc:"Combine si (if) + past subjunctive + conditional to talk about hypothetical, unreal situations.",goals:["Understand the si + imperfecto subjuntivo + condicional structure","Talk about unreal present situations","Express what you would do in imaginary scenarios"]},
        {type:"teach",trg:"Si tuviera dinero, viajaría",src:"If I had money, I would travel",pos:"intj",gender:null,phonetic:"see too-VYEH-ra dee-NEH-ro vya-ha-REE-a",note:"Si + imperfect subjunctive + conditional. The classic hypothetical formula.",example:"A: ¿Qué harías si tuvieras mucho dinero?\nB: Si tuviera dinero, viajaría por todo el mundo.\nA: Yo también haría eso.",exampleSrc:"A: What would you do if you had a lot of money?\nB: If I had money, I would travel around the world.\nA: I would do that too.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Si pudiera, estudiaría",src:"If I could, I would study",pos:"intj",gender:null,phonetic:"see poo-DYEH-ra es-too-dya-REE-a",note:"Si pudiera = if I could. Pudiera is the imperfect subjunctive of poder.",example:"A: ¿Estudiarías otra carrera?\nB: Si pudiera, estudiaría medicina.\nA: Nunca es tarde para empezar.",exampleSrc:"A: Would you study another degree?\nB: If I could, I would study medicine.\nA: It is never too late to start.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Si viviera en España, hablaría español",src:"If I lived in Spain, I would speak Spanish",pos:"intj",gender:null,phonetic:"see vee-VYEH-ra en es-PAN-ya ah-bla-REE-a",note:"The si clause describes the unreal condition, the main clause the imagined result.",example:"A: ¿Cómo mejorarías tu español?\nB: Si viviera en España, hablaría español todo el día.\nA: Podrías ir de intercambio.",exampleSrc:"A: How would you improve your Spanish?\nB: If I lived in Spain, I would speak Spanish all day.\nA: You could do an exchange.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"tip",title:"The hypothetical formula",text:"Si + imperfect subjunctive, + conditional\n\nSi tuviera tiempo, leería más. (If I had time, I would read more.)\nSi fuera rico, no trabajaría. (If I were rich, I would not work.)\n\nThe si clause uses the imperfect subjunctive (tuviera, pudiera, fuera).\nThe main clause uses the conditional (leería, trabajaría).\n\nThese describe situations that are NOT real right now."},
        {type:"teach",trg:"Si fuera posible",src:"If it were possible",pos:"intj",gender:null,phonetic:"see FWEH-ra po-SEE-bleh",note:"Fuera is the imperfect subjunctive of ser. Very common in hypotheticals.",example:"A: Si fuera posible, viviría en el pasado.\nB: ¿En serio? ¿En qué época?\nA: En los años sesenta.",exampleSrc:"A: If it were possible, I would live in the past.\nB: Seriously? In what era?\nA: In the sixties.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Si supiera la respuesta",src:"If I knew the answer",pos:"intj",gender:null,phonetic:"see soo-PYEH-ra la res-PWES-ta",note:"Supiera is the imperfect subjunctive of saber. Means you do NOT know.",example:"A: ¿Por qué no contestas?\nB: Si supiera la respuesta, te la diría.\nA: Nadie la sabe entonces.",exampleSrc:"A: Why don't you answer?\nB: If I knew the answer, I would tell you.\nA: Nobody knows it then.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"mc",q:"'Si tuviera un coche, iría a la playa' means:",opts:["If I had a car, I would go to the beach","I have a car and go to the beach","When I had a car, I went to the beach","I will have a car and go to the beach"],ans:"If I had a car, I would go to the beach",hint:"The si + subjunctive + conditional pattern describes an unreal present situation."},
        {type:"mc",q:"In 'Si pudiera volar, viajaría sin avión', the speaker:",opts:["Can fly","Cannot fly","Used to fly","Will learn to fly"],ans:"Cannot fly",hint:"The hypothetical si clause describes something that is not true right now."},
        {type:"fb",opts:["tuviera","tengo","tendría","tuve"],hint:"If I had. The si clause needs the imperfect subjunctive, not the conditional.",s:"Si {1} más tiempo, estudiaría japonés.",a:"tuviera"},
        {type:"mc",q:"Which part uses the conditional?",opts:["Si tuviera dinero (the if clause)","Both parts use conditional","viajaría por el mundo (the result clause)","Neither part uses conditional"],ans:"viajaría por el mundo (the result clause)",hint:"The si ___ uses the subjunctive. The ___ ___ uses the conditional."},
        {type:"fb",opts:["fuera","sería","es","fue"],hint:"If it were possible. The si clause uses the imperfect subjunctive of ser.",s:"Si {1} posible, cambiaría de trabajo.",a:"fuera"},
        {type:"teach",trg:"Si no lloviera, saldríamos",src:"If it were not raining, we would go out",pos:"intj",gender:null,phonetic:"see no yo-VYEH-ra sal-DREE-a-mos",note:"Negative hypothetical. No in the si clause creates the opposite condition.",example:"A: ¿Salimos al parque?\nB: Si no lloviera, saldríamos. Pero mira el cielo.\nA: Tienes razón, mejor nos quedamos.",exampleSrc:"A: Shall we go to the park?\nB: If it were not raining, we would go out. But look at the sky.\nA: You are right, we better stay.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"drag_fill",hint:"If I spoke (subjunctive in si clause), I would live (conditional in result).",s:"Si {1} español, {2} en Barcelona.",blanks:{"1":"hablara","2":"viviría"},pool:["hablara","viviría","hablaría","viviera"]},
        {type:"match",pairs:[{trg:"Si tuviera",src:"If I had"},{trg:"Si pudiera",src:"If I could"},{trg:"Si fuera",src:"If it were"},{trg:"Si supiera",src:"If I knew"},{trg:"Si viviera",src:"If I lived"}]},
        {type:"mc",q:"'Si fuera presidente, cambiaría las leyes.' The speaker is:",opts:["The president","Running for president","A former president","Not the president"],ans:"Not the president",hint:"Si fuera indicates an unreal condition. The person is imagining."},
        {type:"fb",opts:["supiera","sabría","sé","supe"],hint:"If I knew. The si clause takes the imperfect subjunctive of saber.",s:"Si {1} la respuesta, te la diría.",a:"supiera"},
        {type:"mc",q:"Which sentence is a hypothetical about an unreal situation?",opts:["Si lloviera, llevaría paraguas","Si llueve, llevo paraguas","Cuando llueve, llevo paraguas","Porque llueve, llevo paraguas"],ans:"Si lloviera, llevaría paraguas",hint:"The imperfect subjunctive + conditional combination signals unreality."}
  ]},
  {id:"esp16l6",title:"Sueños",icon:"🌙",xp:15,board:true,steps:[
        {type:"intro",title:"Sueños",desc:"Express your dreams, wishes, and fantasies about life using the conditional tense.",goals:["Talk about life dreams with me gustaría and querría","Describe your ideal life using the conditional","Express wishes about career, travel, and lifestyle"]},
        {type:"teach",trg:"Me gustaría ser médico",src:"I would like to be a doctor",pos:"intj",gender:null,phonetic:"meh goos-ta-REE-a ser MEH-dee-ko",note:"Me gustaría ser + profession for dream careers.",example:"A: ¿Qué querías ser de pequeño?\nB: Me gustaría ser médico. Todavía es mi sueño.\nA: Deberías intentarlo.",exampleSrc:"A: What did you want to be when you were little?\nB: I would like to be a doctor. It is still my dream.\nA: You should try.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Querría vivir en la playa",src:"I would want to live at the beach",pos:"verb",gender:null,phonetic:"keh-RREE-a vee-VEER en la PLA-ya",note:"Querría + infinitive. Slightly more formal than me gustaría.",example:"A: ¿Dónde vivirías si pudieras elegir?\nB: Querría vivir en la playa, cerca del mar.\nA: ¡Qué vida tan tranquila!",exampleSrc:"A: Where would you live if you could choose?\nB: I would want to live at the beach, near the sea.\nA: What a peaceful life!",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"teach",trg:"Soñaría con viajar",src:"I would dream of traveling",pos:"verb",gender:null,phonetic:"so-nya-REE-a kon vya-HAR",note:"Sonar con + infinitive for dreams. Regular conditional: sonar + ía.",example:"A: ¿Con qué sueñas?\nB: Soñaría con viajar por toda América Latina.\nA: Es un sueño muy bonito.",exampleSrc:"A: What do you dream about?\nB: I would dream of traveling through all of Latin America.\nA: That is a very beautiful dream.",funFact:"A regular -ar verb, the largest Spanish verb group. Learn this pattern and you unlock hundreds of verbs."},
        {type:"teach",trg:"Tendría una casa grande",src:"I would have a big house",pos:"intj",gender:null,phonetic:"ten-DREE-a OO-na KA-sa GRAN-deh",note:"Using tendría to describe possessions in your ideal life.",example:"A: ¿Cómo sería tu vida ideal?\nB: Tendría una casa grande con jardín.\nA: ¿Y qué más?",exampleSrc:"A: What would your ideal life be like?\nB: I would have a big house with a garden.\nA: And what else?",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Trabajaría desde casa",src:"I would work from home",pos:"intj",gender:null,phonetic:"tra-ba-ha-REE-a DES-deh KA-sa",note:"Desde casa = from home. Describing an ideal work situation.",example:"A: ¿Cómo sería tu trabajo ideal?\nB: Trabajaría desde casa, sin horarios fijos.\nA: Suena perfecto.",exampleSrc:"A: What would your ideal job be like?\nB: I would work from home, without fixed schedules.\nA: Sounds perfect.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"tip",title:"Dream vocabulary",text:"Common phrases for expressing dreams:\n\nMi sueño sería... = My dream would be...\nEn un mundo ideal... = In an ideal world...\nSi no tuviera obligaciones... = If I had no obligations...\nAlgún día me gustaría... = Someday I would like...\nLo que más querría es... = What I would want most is..."},
        {type:"mc",q:"'Me gustaría ser profesora' expresses:",opts:["She would like to be a teacher","She was a teacher","She is a teacher","She has to be a teacher"],ans:"She would like to be a teacher",hint:"Me gustaría ser + profession describes a dream career."},
        {type:"fb",opts:["Querría","Quiero","Quise","Querré"],hint:"I would want to live. The conditional of querer for a dream.",s:"{1} vivir en un país tropical.",a:"Querría"},
        {type:"mc",q:"Your ideal life: 'Viviría en el campo y ___ animales.'",opts:["tengo","tendría","tuve","tendré"],ans:"tendría",hint:"Describing an imaginary life uses the conditional throughout."},
        {type:"teach",trg:"Sería feliz",src:"I would be happy",pos:"intj",gender:null,phonetic:"seh-REE-a feh-LEES",note:"Ser in the conditional. Sería expresses what your state would be.",example:"A: ¿Serías feliz viviendo en otro país?\nB: Sería feliz si estuviera con mi familia.\nA: La familia es lo más importante.",exampleSrc:"A: Would you be happy living in another country?\nB: I would be happy if I were with my family.\nA: Family is the most important thing.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"fb",opts:["tendría","tengo","tuve","tendré"],hint:"In an ideal world, I would have. Conditional for imaginary situations.",s:"En un mundo ideal, yo {1} más tiempo libre.",a:"tendría"},
        {type:"mc",q:"'Mi sueño sería viajar al espacio' uses the conditional because:",opts:["It happened yesterday","It is happening now","It is an unrealized dream","It is a confirmed plan"],ans:"It is an unrealized dream",hint:"___s that have not come true use the conditional to express the wish."},
        {type:"drag_fill",hint:"I would live (vivir) on an island and I would study (estudiar) sea animals.",s:"{1} en una isla y {2} los animales marinos.",blanks:{"1":"Viviría","2":"estudiaría"},pool:["Viviría","estudiaría","Vivía","estudiaba"]},
        {type:"match",pairs:[
          {trg:"Me gustaría ser",src:"I would like to be"},
          {trg:"Querría vivir",src:"I would want to live"},
          {trg:"Soñaría con",src:"I would dream of"},
          {trg:"Tendría",src:"I would have"},
          {trg:"Sería feliz",src:"I would be happy"}
        ]},
        {type:"mc",q:"Which describes the MOST complete dream?",opts:["Viviría en la playa","Viví en la playa","Vivo en la playa","Viviría en la playa y tendría un barco"],ans:"Viviría en la playa y tendría un barco",hint:"Multiple conditionals paint a richer picture of the imaginary life."},
        {type:"fb",opts:["sería","es","fue","será"],hint:"My dream would be. Ser in the conditional describes an aspiration.",s:"Mi sueño {1} tener mi propia empresa.",a:"sería"},
        {type:"mc",q:"'Algún día me gustaría aprender a tocar la guitarra' means:",opts:["Someday I would like to learn guitar","I played guitar before","I play guitar already","I must learn guitar now"],ans:"Someday I would like to learn guitar",hint:"Algún día = vague future. Me gustaría = conditional of gustar. Tocar is the verb for playing instruments."}
  ]},
  {id:"esp16l7",title:"Yo en tu lugar...",icon:"💡",xp:15,board:true,steps:[
        {type:"intro",title:"Yo en tu lugar...",desc:"Learn to give advice and suggestions using conditional phrases like 'yo en tu lugar' and 'yo que tú'.",goals:["Give advice using yo en tu lugar + conditional","Use yo que tú + conditional for suggestions","Soften advice with the conditional tense"]},
        {type:"teach",trg:"Yo en tu lugar",src:"If I were you / In your place",pos:"verb",gender:null,phonetic:"yo en too loo-GAR",note:"Yo en tu lugar + conditional. A natural way to give personal advice.",example:"A: No sé si aceptar el trabajo.\nB: Yo en tu lugar, lo aceptaría.\nA: ¿Tú crees?",exampleSrc:"A: I don't know if I should accept the job.\nB: If I were you, I would accept it.\nA: You think so?",funFact:"A regular -ar verb, the largest Spanish verb group. Learn this pattern and you unlock hundreds of verbs."},
        {type:"teach",trg:"Yo que tú",src:"If I were you",pos:"verb",gender:null,phonetic:"yo keh TOO",note:"Yo que tú + conditional. Even shorter than yo en tu lugar. Very common.",example:"A: Estoy pensando en dejarlo.\nB: Yo que tú, hablaría primero con él.\nA: Tienes razón, debería hablar.",exampleSrc:"A: I am thinking about leaving him.\nB: If I were you, I would talk to him first.\nA: You are right, I should talk.",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"teach",trg:"Yo no haría eso",src:"I would not do that",pos:"verb",gender:null,phonetic:"yo no ah-REE-a EH-so",note:"A gentle warning. Using the conditional softens the disagreement.",example:"A: Voy a decirle lo que pienso.\nB: Yo no haría eso. Podría enfadarse.\nA: Tal vez tienes razón.",exampleSrc:"A: I am going to tell her what I think.\nB: I would not do that. She could get angry.\nA: Maybe you are right.",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"teach",trg:"¿No sería mejor...?",src:"Wouldn't it be better...?",pos:"intj",gender:null,phonetic:"no seh-REE-a meh-HOR",note:"A polite way to suggest an alternative. The question form softens it further.",example:"A: Voy a ir en coche.\nB: ¿No sería mejor ir en tren? Hay mucho tráfico.\nA: Buena idea, iré en tren.",exampleSrc:"A: I am going to go by car.\nB: Wouldn't it be better to go by train? There is a lot of traffic.\nA: Good idea, I will go by train.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Podrías intentar",src:"You could try",pos:"verb",gender:null,phonetic:"po-DREE-as in-ten-TAR",note:"Podrías + infinitive is soft advice. You are suggesting, not commanding.",example:"A: No puedo dormir por las noches.\nB: Podrías intentar leer antes de dormir.\nA: Nunca lo he probado.",exampleSrc:"A: I can't sleep at night.\nB: You could try reading before bed.\nA: I have never tried that.",funFact:"A regular -ar verb, the largest Spanish verb group. Learn this pattern and you unlock hundreds of verbs."},
        {type:"tip",title:"Softening advice with the conditional",text:"Direct: Debes ir al médico. (You must go to the doctor.)\nSoft: Deberías ir al médico. (You should go to the doctor.)\nSofter: Yo que tú, iría al médico. (If I were you, I'd go.)\nSoftest: ¿No sería mejor ir al médico? (Wouldn't it be better to go?)\n\nThe conditional lets you give advice without sounding bossy."},
        {type:"mc",q:"'Yo en tu lugar, no diría nada' means:",opts:["In your place, I would say nothing","I said nothing","You should say nothing","I am saying nothing"],ans:"In your place, I would say nothing",hint:"Yo en tu lugar is a conditional advice phrase. Diría = conditional of decir."},
        {type:"mc",q:"Which is the SOFTEST way to suggest seeing a doctor?",opts:["Ve al médico","¿No sería mejor ir al médico?","Deberías ir al médico","Debes ir al médico"],ans:"¿No sería mejor ir al médico?",hint:"The question form with the conditional is the gentlest suggestion."},
        {type:"fb",opts:["hablaría","hablo","hablé","hablaré"],hint:"If I were you, I would talk. The conditional follows the advice phrase.",s:"Yo que tú, {1} con ella antes de decidir.",a:"hablaría"},
        {type:"mc",q:"A friend says 'Voy a dejar mi trabajo.' You gently advise against it:",opts:["¡No lo hagas!","Lo dejé también","Yo no haría eso","Déjalo ya"],ans:"Yo no haría eso",hint:"Using the conditional expresses gentle disagreement, not a command."},
        {type:"fb",opts:["sería","es","fue","será"],hint:"Wouldn't it be better? Ser in the conditional for a gentle suggestion.",s:"¿No {1} mejor esperar un poco?",a:"sería"},
        {type:"teach",trg:"Yo cambiaría de estrategia",src:"I would change strategy",pos:"verb",gender:null,phonetic:"yo kam-bya-REE-a deh es-tra-TEH-hya",note:"Giving professional advice using the conditional. Direct but polite.",example:"A: Mis ventas no mejoran.\nB: Yo cambiaría de estrategia. ¿Has probado las redes sociales?\nA: No, pero podría intentarlo.",exampleSrc:"A: My sales are not improving.\nB: I would change strategy. Have you tried social media?\nA: No, but I could try.",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"teach",trg:"Lo mejor sería",src:"The best thing would be",pos:"verb",gender:null,phonetic:"lo meh-HOR seh-REE-a",note:"Lo mejor sería + infinitive. A calm, objective way to recommend action.",example:"A: ¿Qué hago con este problema?\nB: Lo mejor sería hablar con un abogado.\nA: Sí, creo que es necesario.",exampleSrc:"A: What should I do about this problem?\nB: The best thing would be to talk to a lawyer.\nA: Yes, I think it is necessary.",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"drag_fill",hint:"In your place I would leave (dejar) the job and I would look for (buscar) another.",s:"Yo en tu lugar {1} el trabajo y {2} otro.",blanks:{"1":"dejaría","2":"buscaría"},pool:["dejaría","buscaría","dejó","buscó"]},
        {type:"match",pairs:[
          {trg:"Yo en tu lugar",src:"If I were you (in your place)"},
          {trg:"Yo que tú",src:"If I were you (short form)"},
          {trg:"Yo no haría eso",src:"I would not do that"},
          {trg:"Podrías intentar",src:"You could try"},
          {trg:"Lo mejor sería",src:"The best thing would be"}
        ]},
        {type:"mc",q:"A colleague asks for career advice. You say:",opts:["Debes cambiar de trabajo","Nunca cambies","Cambia de trabajo ahora","Yo que tú, buscaría nuevas oportunidades"],ans:"Yo que tú, buscaría nuevas oportunidades",hint:"The yo ___ tú formula gives personal advice without being pushy."},
        {type:"fb",opts:["Podrías","Puedes","Podías","Podrás"],hint:"You could try. The conditional of poder for a gentle suggestion.",s:"{1} intentar otro método. Este no funciona.",a:"Podrías"},
        {type:"mc",q:"'Lo mejor sería descansar unos días' is:",opts:["A calm recommendation to rest","A command to rest","A question about resting","A past event about resting"],ans:"A calm recommendation to rest",hint:"Lo mejor sería introduces what the speaker considers the wisest course of action."}
  ]},
  {id:"esp16l8",title:"Un mundo ideal",icon:"🎯",xp:20,board:true,steps:[
        {type:"intro",title:"Un mundo ideal",desc:"Bring together everything about the conditional: polite requests, hypotheticals, dreams, and advice.",goals:["Use the conditional for politeness, dreams, and hypotheticals","Distinguish conditional from future and present","Combine si + subjunctive with the conditional"]},
        {type:"mc",q:"The conditional of 'hablar' (yo) is:",opts:["hablaría","hablaré","hablaba","hablé"],ans:"hablaría",hint:"Full infinitive + the ending that includes an accented i."},
        {type:"fb",opts:["tuviera","tendría","tengo","tuve"],hint:"If I had. The si clause uses the imperfect subjunctive, not the conditional.",s:"Si {1} dinero, compraría una casa.",a:"tuviera"},
        {type:"mc",q:"'¿Podría ayudarme?' is best described as:",opts:["A rude demand","A polite request","A past tense question","A future plan"],ans:"A polite request",hint:"The conditional of poder makes ___s courteous and respectful."},
        {type:"teach",trg:"En un mundo ideal, todos hablaríamos español",src:"In an ideal world, we would all speak Spanish",pos:"intj",gender:null,phonetic:"en oon MOON-do ee-deh-AL TO-dos ah-bla-REE-a-mos es-pa-NYOL",note:"Combining a dream scenario with the conditional. Nosotros form.",example:"A: ¿Cuántos idiomas hablas?\nB: Solo dos. En un mundo ideal, todos hablaríamos cinco idiomas.\nA: Sería increíble, sí.",exampleSrc:"A: How many languages do you speak?\nB: Only two. In an ideal world, we would all speak five languages.\nA: It would be incredible, yes.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"mc",q:"The conditional uses the same irregular stems as:",opts:["The present tense","The preterite","The future tense","The imperfect"],ans:"The future tense",hint:"Both ___s modify the same set of verbs in the same way."},
        {type:"fb",opts:["haría","hago","hice","haré"],hint:"I would not do that. Hacer in the conditional with its irregular stem.",s:"Yo que tú, no {1} eso.",a:"haría"},
        {type:"drag_fill",hint:"If we passed (subjunctive in si clause), we would go out (conditional in result).",s:"Si {1} el examen, {2} a celebrar.",blanks:{"1":"aprobara","2":"saldríamos"},pool:["aprobara","saldríamos","aprobaría","salimos"]},
        {type:"mc",q:"'Deberías descansar' gives:",opts:["A direct order","A future promise","A past fact","Gentle advice"],ans:"Gentle advice",hint:"The conditional of deber softens the suggestion."},
        {type:"fb",opts:["gustaría","gusta","gustó","gustará"],hint:"I would like to visit Japan someday. Conditional for a wish.",s:"Me {1} conocer Japón algún día.",a:"gustaría"},
        {type:"mc",q:"Which sentence correctly uses the hypothetical formula?",opts:["Si tuviera dinero, viajaría","Si tengo dinero, viajaré","Si tendría dinero, viajaría","Si tuviera dinero, viajo"],ans:"Si tuviera dinero, viajaría",hint:"Si + imperfect subjunctive in the if clause, conditional in the result clause."},
        {type:"match",pairs:[{trg:"hablaría",src:"I would speak"},{trg:"tendría",src:"I would have"},{trg:"haría",src:"I would do"},{trg:"podría",src:"I could"},{trg:"diría",src:"I would say"},{trg:"sería",src:"I would be"}]},
        {type:"fb",opts:["importaría","importa","importó","importará"],hint:"Would you mind? Very formal polite request in the conditional.",s:"¿Le {1} repetir la dirección, por favor?",a:"importaría"},
        {type:"mc",q:"'Si fuera rico, no trabajaría.' The speaker:",opts:["Is rich and does not work","Is not rich and does work","Was rich in the past","Will become rich soon"],ans:"Is not rich and does work",hint:"The hypothetical describes the opposite of the speaker's reality."},
        {type:"drag_fill",hint:"I would do more sport (hacer, irregular) and eat less fast food (comer, regular).",s:"Yo {1} más deporte y {2} menos comida rápida.",blanks:{"1":"haría","2":"comería"},pool:["haría","comería","hago","como"]},
        {type:"mc",q:"Which is the most polite way to ask for water in a restaurant?",opts:["Dame agua","Quiero agua","¿Me podría traer agua, por favor?","Necesito agua"],ans:"¿Me podría traer agua, por favor?",hint:"___ + por ___ creates the most courteous request."},
        {type:"fb",opts:["estuviera","estaría","estoy","estuve"],hint:"If I were in your place. The si clause uses the imperfect subjunctive of estar.",s:"Si {1} en tu lugar, aceptaría la oferta.",a:"estuviera"},
        {type:"mc",q:"Which pair shows the correct future vs conditional of 'tener'?",opts:["tendiré / tendiría","teneré / tenería","tenré / tenría","tendré / tendría"],ans:"tendré / tendría",hint:"Same irregular stem tendr- with different endings: -é for future, -ía for conditional."},
        {type:"drag_fill",hint:"The best thing would be (ser conditional) to talk to a lawyer.",s:"Lo mejor {1} hablar con un {2}.",blanks:{"1":"sería","2":"abogado"},pool:["sería","abogado","será","médico"]}
  ]},
  {id:"esp16l8b",title:"La Tecnología",icon:"💻",xp:15,board:true,steps:[
        {type:"intro",title:"La Tecnología",desc:"Learn vocabulary for everyday technology: computers, phones, and the internet.",goals:["Learn 13 technology words with el/la","Talk about using devices and apps","Know regional differences: ordenador vs computadora"]},
        {type:"teach",trg:"el ordenador",src:"the computer (Spain)",pos:"noun",gender:"m",phonetic:"el or-deh-nah-DOR",note:"el ordenador: used in Spain.\nIn Latin America: la computadora.\nBoth are correct.",example:"A: ¿Dónde está tu ordenador?\nB: Está en mi escritorio.\nA: ¿Es nuevo?\nB: Sí, lo compré la semana pasada.",exampleSrc:"A: Where is your computer?\nB: It's on my desk.\nA: Is it new?\nB: Yes, I bought it last week.",deepDive:{
          title:"Ordenador vs Computadora",
          text:"In Spain, 'el ordenador' is standard. In Latin America, 'la computadora' is universal. In formal international Spanish, both are understood. Note the gender difference: el ordenador (masculine) vs la computadora (feminine)."
        ,funFact:"Masculine noun. Spanish words ending in -o are usually masculine."}},
        {type:"teach",trg:"la computadora",src:"the computer (Latin America)",pos:"noun",gender:"f",phonetic:"lah kom-poo-tah-DOH-rah",note:"la computadora: used in Latin America.\nFeminine noun.\nIn Spain: el ordenador.",example:"A: Necesito una computadora nueva.\nB: ¿Para qué la necesitas?\nA: Para trabajar desde casa.\nB: Hay buenas ofertas en línea.",exampleSrc:"A: I need a new computer.\nB: What do you need it for?\nA: To work from home.\nB: There are good deals online.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"teach",trg:"el teléfono móvil",src:"the mobile phone",pos:"noun",gender:"m",phonetic:"el teh-LEH-foh-noh MOH-beel",note:"Often shortened to 'el móvil' in Spain.\nIn Latin America: el celular.",example:"A: ¿Tienes tu móvil?\nB: Sí, siempre llevo el móvil conmigo.\nA: ¿Me puedes dar tu número?\nB: Claro, es el 612 345 678.",exampleSrc:"A: Do you have your mobile?\nB: Yes, I always carry my mobile with me.\nA: Can you give me your number?\nB: Sure, it's 612 345 678.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el internet",src:"the internet",pos:"noun",gender:"m",phonetic:"el een-ter-NET",note:"el internet: masculine in most countries.\nSome say 'la internet' (feminine).",example:"A: ¿Tienes internet en casa?\nB: Sí, pero a veces es lento.\nA: ¿Qué operador usas?\nB: Uso Movistar.",exampleSrc:"A: Do you have internet at home?\nB: Yes, but sometimes it's slow.\nA: Which provider do you use?\nB: I use Movistar.",funFact:"Cognate with English 'internet'. Spanish and English share many Latin-derived words."},
        {type:"teach",trg:"el correo electrónico",src:"the email",pos:"noun",gender:"m",phonetic:"el koh-RREH-oh eh-lek-TROH-nee-koh",note:"Often shortened to 'el correo'.\nEnviar un correo = to send an email.",example:"A: ¿Me puedes enviar un correo electrónico?\nB: Sí, ¿cuál es tu dirección?\nA: Es maria@correo.com.\nB: Te lo envío esta tarde.",exampleSrc:"A: Can you send me an email?\nB: Yes, what is your address?\nA: It's maria@correo.com.\nB: I'll send it to you this afternoon.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el mensaje",src:"the message",pos:"noun",gender:"m",phonetic:"el men-SAH-heh",note:"el mensaje: masculine.\nEnviar/mandar un mensaje = to send a message.\nMensaje de texto = text message.",example:"A: ¿Recibiste mi mensaje?\nB: Sí, lo leí esta mañana.\nA: ¿Y qué te parece?\nB: Me parece bien, acepto.",exampleSrc:"A: Did you receive my message?\nB: Yes, I read it this morning.\nA: And what do you think?\nB: I think it's fine, I accept.",funFact:"Cognate with English 'message'. Spanish and English share many Latin-derived words."},
        {type:"teach",trg:"la contraseña",src:"the password",pos:"noun",gender:"f",phonetic:"lah kon-trah-SEH-nyah",note:"la contraseña: feminine.\nCambiar la contraseña = to change the password.",example:"A: No recuerdo mi contraseña.\nB: Puedes cambiarla en la configuración.\nA: ¿Cómo?\nB: Haz clic en 'Olvidé mi contraseña'.",exampleSrc:"A: I don't remember my password.\nB: You can change it in settings.\nA: How?\nB: Click on 'I forgot my password'.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"teach",trg:"la pantalla",src:"the screen",pos:"noun",gender:"f",phonetic:"lah pan-TAH-yah",note:"la pantalla: feminine.\nPantalla táctil = touchscreen.",example:"A: La pantalla de mi móvil está rota.\nB: ¿La puedes reparar?\nA: Sí, hay una tienda cerca.\nB: Te acompaño si quieres.",exampleSrc:"A: My phone screen is broken.\nB: Can you repair it?\nA: Yes, there's a shop nearby.\nB: I'll come with you if you want.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"teach",trg:"el cargador",src:"the charger",pos:"noun",gender:"m",phonetic:"el kar-gah-DOR",note:"el cargador: masculine.\nCargar el móvil = to charge the phone.",example:"A: ¿Tienes un cargador?\nB: Sí, ¿para qué tipo de móvil?\nA: Para un USB-C.\nB: Toma, puedes usar el mío.",exampleSrc:"A: Do you have a charger?\nB: Yes, for what type of phone?\nA: For a USB-C.\nB: Here, you can use mine.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"la aplicación",src:"the app / application",pos:"noun",gender:"f",phonetic:"lah ah-plee-kah-SYOHN",note:"la aplicación: feminine.\nOften shortened to 'la app' [ap].",example:"A: ¿Qué aplicación usas para las fotos?\nB: Uso Instagram.\nA: ¿Y para mensajes?\nB: WhatsApp, como todo el mundo.",exampleSrc:"A: What app do you use for photos?\nB: I use Instagram.\nA: And for messages?\nB: WhatsApp, like everyone.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"teach",trg:"buscar",src:"to search",pos:"verb",gender:null,phonetic:"boos-KAR",note:"buscar: to search, to look for.\nBuscar en internet = to search online.",example:"A: ¿Puedes buscar un restaurante?\nB: Sí, lo busco en Google.\nA: Busca uno cerca de aquí.\nB: He encontrado tres opciones.",exampleSrc:"A: Can you search for a restaurant?\nB: Yes, I'll search for it on Google.\nA: Search for one near here.\nB: I've found three options.",funFact:"A regular -ar verb, the largest Spanish verb group. Learn this pattern and you unlock hundreds of verbs."},
        {type:"teach",trg:"descargar",src:"to download",pos:"verb",gender:null,phonetic:"des-kar-GAR",note:"descargar: to download.\nDescargar una aplicación = to download an app.",example:"A: ¿Has descargado la nueva aplicación?\nB: No, todavía no.\nA: Es gratis, descárgala.\nB: Vale, la descargo ahora.",exampleSrc:"A: Have you downloaded the new app?\nB: No, not yet.\nA: It's free, download it.\nB: OK, I'll download it now.",funFact:"A regular -ar verb, the largest Spanish verb group. Learn this pattern and you unlock hundreds of verbs."},
        {type:"teach",trg:"la foto",src:"the photo",pos:"noun",gender:"f",phonetic:"lah FOH-toh",note:"la foto: feminine (short for la fotografía).\nHacer/sacar una foto = to take a photo.",example:"A: ¿Me puedes hacer una foto?\nB: Claro, ¿aquí?\nA: Sí, con la catedral detrás.\nB: Sonríe. ¡Ya está!",exampleSrc:"A: Can you take a photo of me?\nB: Sure, here?\nA: Yes, with the cathedral behind.\nB: Smile. Done!",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"tip",title:"Regional Tech Vocabulary",text:"Many tech words differ between Spain and Latin America:\n\n. el ordenador (Spain) = la computadora (LatAm)\n. el móvil (Spain) = el celular (LatAm)\n. el correo electrónico = el email/e-mail (informal)\n\nBoth forms are widely understood. LingoVerse teaches both so you can communicate anywhere."},
        {type:"mc",q:"What is 'the password' in Spanish?",opts:["la contraseña","el mensaje","la pantalla","el correo"],ans:"la contraseña",hint:"Think of the word that contains 'seña' (sign/signal)."},
        {type:"fb",opts:["descargar","buscar","cargar","enviar"],hint:"Which verb means to download something onto a device?",s:"Voy a {1} la nueva aplicación en mi móvil.",a:"descargar"},
        {type:"mc",q:"In Spain, 'the computer' is:",opts:["la computadora","el ordenador","el computador","la ordenadora"],ans:"el ordenador",hint:"In Spain the masculine form is standard. Latin America uses a different word."},
        {type:"match",pairs:[{trg:"el correo electrónico",src:"email"},{trg:"la contraseña",src:"password"},{trg:"la pantalla",src:"screen"},{trg:"el cargador",src:"charger"},{trg:"la aplicación",src:"app"}]},
        {type:"fb",opts:["contraseña","pantalla","mensaje","foto"],hint:"What do you need to enter to log into your account?",s:"No recuerdo mi {1}. No puedo entrar en mi cuenta.",a:"contraseña"},
        {type:"drag_fill",hint:"I'm going to search for a restaurant on the internet.",s:"Voy a {1} un restaurante en {2}.",blanks:{"1":"buscar","2":"internet"},pool:["buscar","internet","descargar","mensaje"]}
  ]}
]};
